//# Simulation Clock

// *This text is mostly lifted from the [Simulated Clock
// Generation](./verilog.html#clock) section of my Verilog Coding Standard.
// Credit goes to Claire Wolf ([@oe1cxw](https://twitter.com/oe1cxw)) for
// teaching me this finer point of Verilog simulation.*

// **NOTE: This code cannot work in Verilator, which can only simulate
// synthesizable Verilog, and thus does not support delayed assignments.**
// Simulate the clock in the C++ testbench instead, or if you must use
// Verilog, try the Icarus Verilog simulator.

//**NOTE: This clock cannot be used directly as a periodic data signal.** It
//causes a race condition in the Verilog simulation event queue. I have not
//yet found a solution.

// In simulation, a race condition can exist at time zero between the initial
// value assignment of a register and the first clock edge. For example:

//    reg clock = 1'b0; // Counts as a negedge at time zero! (1'bX -> 1'b0)
//    reg foo   = 1'b0; // Also does 1'bX -> 1'b0 at time zero.
//    reg bar   = 1'b0;
//
//    // Simulate the clock
//    always begin
//        #HALF_PERIOD clock = ~clock;
//    end
//
//    // Use the simulated clock
//    always @(negedge clock) begin
//        bar <= foo;
//    end

// In the code above, it is unclear if the initial negative clock edge or the
// initialization of `foo` will simulate first, so `bar` might get assigned
// 1'bX for the first simulation cycle, which is not what the code intends.
// This race condition is another reason to only use `@(posedge clock)` in
// internal logic, but the same race condition will happen if the simulation
// clock happens to be initialized to 1'b1.

// Instead, the following clock simulation idiom avoids the race condition by
// making use of undefined values and the identity operator `===`, which
// matches X values exactly, instead of the equality `==` operator which
// treats X as false: we leave the clock uninitialized to 1'bX, and compare it
// by identity after one clock half-period delay, which then assigns it false
// (1'b0).

`default_nettype none

`timescale 1ns / 1ps

module Simulation_Clock
#(
    parameter CLOCK_PERIOD = 10
)
(
    output reg clock
);

    localparam HALF_PERIOD = CLOCK_PERIOD / 2;

    always begin
        #HALF_PERIOD clock = (clock === 1'b0);
    end

endmodule

// Additionally, the following tidbits are handy to use with the resulting
// clock.  If you use `WAIT_CYCLES` or `UNTIL_CYCLE` exclusively to time
// actions, without using `#` delays, then a `timescale` directive is not
// necessary anywhere else, and your simulation will run at the correct
// simulated rate.

//    `define WAIT_CYCLES(n) repeat (n) begin @(posedge clock); end
//
//    time cycle = 0; 
//
//    always @(posedge clock) begin
//        cycle = cycle + 1;
//    end
//
//    `define UNTIL_CYCLE(n) wait (cycle == n);

//# Synthesis Harness Input

// When developing a new module, it's very convenient to run it through your
// CAD tool by itself, on a smaller target FPGA, with any random automatic pin
// assignments, to iterate quickly and find synth and timing issues.
// However, you can run out of physical pins, and your logic will get
// scattered all over the FPGA as it tries to stay close to the pins, wrecking
// your timing estimates.  Also, any input or output logic which isn't
// registered won't be part of the STA (Static Timing Analysis), so that also
// makes the timing estimate less accurate when synthesized in isolation.

// A solution to both problems is to place your design in a harness of
// registers. For the inputs, we feed them all from a shift register fed by
// only a few pins (clock, reset, enable, input, etc...), which virtually
// eliminates the problem of running out of pins, while still avoiding
// optimizing away any logic by accident since no inputs are constant or
// predictable. The inputs are meaningless for simulation, but that's not what
// we need them for right now.

// You must also constrain the harness registers to *not* be placed in the
// FPGA I/O registers so they will cluster around your logic, which will now
// tend to place all together in the center of the FPGA, giving you
// a reasonnably accurate timing estimate. 

// You can make the timing estimate more conservative by logically partioning
// the netlists of the design and the harness so they do not retime into
// eachother. You can make the timing estimate *even more* conservative by
// additionally physically partitioning (a.k.a. floorplanning) the netlists:
// place your design into a floorplan rectangle (or let the CAD tool do it
// automatically) and exclude the harness, which will then cluster around the
// design floorplan and approximate either connection from adjacent
// floorplans, or logic forced apart by congestion.

// A good way to use this module is to add up the widths of all your design
// inputs and use that sum as the `WORD_WIDTH` parameter, then connect
// a concatenation of all your input wires to the `word_out` port. The
// remaining harness ports can be connected to any suitable device pins.

// The counterpart to this module is the [Synthesis Harness
// Output](./Synthesis_Harness_Output.html).

`default_nettype none

module Synthesis_Harness_Input
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire                        clock,  
    input   wire                        clear,
    input   wire                        bit_in,
    input   wire                        bit_in_valid,
    output  wire    [WORD_WIDTH-1:0]    word_out
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    // Vivado: don't put in I/O buffers, and keep netlists separate in
    // synth and implementation.
    (* IOB = "false" *)
    (* DONT_TOUCH = "true" *)

    // Quartus: don't use I/O buffers, and don't merge registers with others.
    (* useioff = 0 *)
    (* preserve *)

    Register_Pipeline
    #(
        .WORD_WIDTH     (1),
        .PIPE_DEPTH     (WORD_WIDTH),
        .RESET_VALUES   (WORD_ZERO)
    )
    shift_bit_into_word
    (
        .clock          (clock),
        .clock_enable   (bit_in_valid),
        .clear          (clear),
        .parallel_load  (1'b0),
        .parallel_in    (WORD_ZERO),
        .parallel_out   (word_out),
        .pipe_in        (bit_in),
        // verilator lint_off PINCONNECTEMPTY
        .pipe_out       ()
        // verilator lint_on  PINCONNECTEMPTY
    );

endmodule

//# Synthesis Harness Output

// When developing a new module, it's very convenient to run it through your
// CAD tool by itself, on a smaller target FPGA, with any random automatic pin
// assignments, to iterate quickly and find synth and timing issues.
// However, you can run out of physical pins, and your logic will get
// scattered all over the FPGA as it tries to stay close to the pins, wrecking
// your timing estimates.  Also, any input or output logic which isn't
// registered won't be part of the STA (Static Timing Analysis), so that also
// makes the timing estimate less accurate when synthesized in isolation.

// A solution to both problems is to place your design in a harness of
// registers. For the outputs, we connect them all to a final bank of
// registers whose outputs are then XOR-reduced to a single bit, which
// virtually eliminates the problem of running out of pins, while still
// avoiding optimizing away any logic by accident since that final output is
// completely data-dependent. The output is meaningless for simulation, but
// that's not what we need it for right now.

// It would seem natural to do the reverse of the [Synthesis Harness
// Input](./Synthesis_Harness_Input.html) and do a parallel-to-serial
// conversion to the output bits to a single bit, but that might
// pollute our timing analysis since synth might create multiplexers
// between the outputs and the registers. So we bit-reduce instead.

// You must also constrain the harness registers to *not* be placed in the
// FPGA I/O registers so they will cluster around your logic, which will now
// tend to place all together in the center of the FPGA, giving you
// a reasonnably accurate timing estimate. 

// You can make the timing estimate more conservative by logically partioning
// the netlists of the design and the harness so they do not retime into
// eachother. You can make the timing estimate *even more* conservative by
// additionally physically partitioning (a.k.a. floorplanning) the netlists:
// place your design into a floorplan rectangle (or let the CAD tool do it
// automatically) and exclude the harness, which will then cluster around the
// design floorplan and approximate either connection from adjacent
// floorplans, or logic forced apart by congestion.

// A good way to use this module is to add up the widths of all your design
// outputs and use that sum as the `WORD_WIDTH` parameter, then connect
// a concatenation of all your output wires to the `word_in` port. The
// remaining harness ports can be connected to any suitable device pins.

`default_nettype none

module Synthesis_Harness_Output 
#(
    parameter   WORD_WIDTH = 0
)
(
    input       wire                        clock,
    input       wire                        clear,
    input       wire    [WORD_WIDTH-1:0]    word_in,
    input       wire                        word_in_valid,
    output      reg                         bit_out
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        bit_out = 1'b0;
    end

    wire [WORD_WIDTH-1:0] word_out;

    // Vivado: don't put in I/O buffers, and keep netlists separate in
    // synth and implementation.
    (* IOB = "false" *)
    (* DONT_TOUCH = "true" *)

    // Quartus: don't use I/O buffers, and don't merge registers with others.
    (* useioff = 0 *)
    (* preserve *)

    Register_Pipeline
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .PIPE_DEPTH     (1),
        .RESET_VALUES   (WORD_ZERO)
    )
    word_register
    (
        .clock          (clock),
        .clock_enable   (word_in_valid),
        .clear          (clear),
        .parallel_load  (1'b0),
        .parallel_in    (WORD_ZERO),
        // verilator lint_off PINCONNECTEMPTY
        .parallel_out   (),
        // verilator lint_on  PINCONNECTEMPTY
        .pipe_in        (word_in),
        .pipe_out       (word_out)
    );

    always @(*) begin
        bit_out = ^word_out;
    end

endmodule

